import{_ as e,o,c as i,a2 as r}from"./chunks/framework.CdOEJW8E.js";const h=JSON.parse('{"title":"Orientações","description":"","frontmatter":{},"headers":[],"relativePath":"orientacoes.md","filePath":"orientacoes.md"}'),s={name:"orientacoes.md"};function l(n,a,t,d,c,u){return o(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="orientacoes" tabindex="-1">Orientações <a class="header-anchor" href="#orientacoes" aria-label="Permalink to &quot;Orientações&quot;">​</a></h1><h2 id="escolha-dos-cantos" tabindex="-1">Escolha dos Cantos <a class="header-anchor" href="#escolha-dos-cantos" aria-label="Permalink to &quot;Escolha dos Cantos&quot;">​</a></h2><ul><li>A escolha dos cantos deve ser feita levando-se em consideração: <ul><li>A Liturgia do Dia</li><li>O Tempo Litúrgico</li><li>As Orientações Paroquiais e Diocesanas quando houver</li></ul></li></ul><h2 id="os-momentos-da-missa" tabindex="-1">Os Momentos da Missa <a class="header-anchor" href="#os-momentos-da-missa" aria-label="Permalink to &quot;Os Momentos da Missa&quot;">​</a></h2><h3 id="refrao-orante" tabindex="-1">Refrão Orante <a class="header-anchor" href="#refrao-orante" aria-label="Permalink to &quot;Refrão Orante&quot;">​</a></h3><ul><li>Objetiva criar um ambiente propício para a celebração.</li><li>Deve ser repetitivo e suave.</li><li>Deve remeter à liturgia do dia ou ao tempo litúrgico.</li></ul><h3 id="abertura" tabindex="-1">Abertura <a class="header-anchor" href="#abertura" aria-label="Permalink to &quot;Abertura&quot;">​</a></h3><ul><li>Canto processional.</li><li>Dar preferência para cantos inspirados na antífona do dia contida no Missal, do hinário litúrgico da CNBB.</li></ul><h3 id="ato-penitencial" tabindex="-1">Ato Penitencial <a class="header-anchor" href="#ato-penitencial" aria-label="Permalink to &quot;Ato Penitencial&quot;">​</a></h3><ul><li>Deve-se seguir obrigatoriamente as fórmulas do Missal.</li><li>Não se deve alterar o sentido das invocações que estão no Missal.</li></ul><h3 id="gloria" tabindex="-1">Glória <a class="header-anchor" href="#gloria" aria-label="Permalink to &quot;Glória&quot;">​</a></h3><ul><li>A única letra aprovada do Glória é a que se encontra no Missal.</li><li>O Glória é cantado ou recitado: <ul><li>Nos domingos, exceto nos domingos do Advento e da Quaresma.</li><li>Nas solenidades e festas.</li><li>Em celebrações particulares mais solenes, mesmo que não sejam domingo, solenidade ou festa, quando a celebração tem caráter especial de solenidade.</li></ul></li></ul><h3 id="refrao-orante-1" tabindex="-1">Refrão Orante <a class="header-anchor" href="#refrao-orante-1" aria-label="Permalink to &quot;Refrão Orante&quot;">​</a></h3><ul><li>Não previsto na liturgia.</li><li>Objetiva preparar a assembleia para Liturgia da Palavra enquanto o leitor se dirige ao ambão.</li><li>Deve ser breve, suave.</li></ul><h3 id="salmo" tabindex="-1">Salmo <a class="header-anchor" href="#salmo" aria-label="Permalink to &quot;Salmo&quot;">​</a></h3><ul><li>Deve ser cantado do Ambão.</li><li>Deve possuir melodia simples para que o povo responda ao ouvir apenas uma vez.</li><li>Em vez do salmo que vem indicado no Lecionário, também se pode cantar ou o responsório gradual tirado do Gradual Romano ou um salmo responsorial ou aleluiático do Gradual simples, na forma indicada nestes livros.(IGMR-61)</li></ul><h3 id="aclamacao-ao-evangelho" tabindex="-1">Aclamação ao Evangelho <a class="header-anchor" href="#aclamacao-ao-evangelho" aria-label="Permalink to &quot;Aclamação ao Evangelho&quot;">​</a></h3><ul><li>O Aleluia canta-se em todos os tempos fora da Quaresma. Os versículos tomam-se do Lecionário ou do Gradual</li><li>Na Quaresma, em vez do Aleluia canta-se o versículo antes do Evangelho que vem no Lecionário. Também se pode cantar outro salmo ou trato, como se indica no Gradual.</li><li>Atentar-se para as missas feriais que não possuem a Segunda Leitura, pois a Aclamação ao Evangelho é cantada imediatamente após o Salmo.</li></ul><h3 id="oferta" tabindex="-1">Oferta <a class="header-anchor" href="#oferta" aria-label="Permalink to &quot;Oferta&quot;">​</a></h3><ul><li>Canto processional.</li><li>Nas celebrações da palavra não se deve cantar cantos que fazem referência a ofertas de vinho e de pão pois estas ofertas ocorrem apenas na Missa.</li><li>Dar preferência a cantos que remetam à antífona de oferta do Gradual.</li></ul><h3 id="santo" tabindex="-1">Santo <a class="header-anchor" href="#santo" aria-label="Permalink to &quot;Santo&quot;">​</a></h3><ul><li>Pode ser cantado ou rezado (É preciso combinar com o Padre conforme costume do local)</li><li>A letra do Santo não deve diferir do Missal.</li><li>Não se canta o Santo nas celebrações da Palavra.</li><li>O Santo é uma oração direcionada à Deus.</li><li>Quando na letra do Santo estiver “Santo, Santo, Santo é o Senhor”, deverá ser omitido o “é o” para manter o sentido litúrgico da oração, permanecendo conforme a letra “Santo, Santo, Santo, Senhor Deus do Universo”.</li><li><a href="https://www.cnbb.org.br/o-cantico-do-santo-na-oracao-eucaristica-na-visao-de-alguns-padres-da-igreja/" target="_blank" rel="noreferrer">Artigo da CNBB sobre o Santo</a></li></ul><h3 id="oracao-eucaristica" tabindex="-1">Oração Eucarística <a class="header-anchor" href="#oracao-eucaristica" aria-label="Permalink to &quot;Oração Eucarística&quot;">​</a></h3><ul><li>Pode ser cantada</li></ul><h3 id="doxologia-final-e-grande-amem" tabindex="-1">Doxologia Final e Grande Amém <a class="header-anchor" href="#doxologia-final-e-grande-amem" aria-label="Permalink to &quot;Doxologia Final e Grande Amém&quot;">​</a></h3><ul><li>Pode ser cantado ou rezado</li></ul><h3 id="paz" tabindex="-1">Paz <a class="header-anchor" href="#paz" aria-label="Permalink to &quot;Paz&quot;">​</a></h3><ul><li>A <em>Carta Circular sobre o significado ritual do dom da paz na Missa</em> recorda que o rito da paz tem sentido próprio na liturgia romana e deve ser realizado com sobriedade, sem se tornar ocasião de dispersão antes da Comunhão.</li><li>O grupo de canto deve aguardar o início do Cordeiro, pois a carta aponta como abuso a introdução de um canto para a paz no Rito Romano.</li></ul><p>Fonte: <a href="https://dj.org.br/wp-content/uploads/2020/10/Carta-circular-o-significado-da-paz-na-missa.pdf" target="_blank" rel="noreferrer">Carta circular: O significado ritual do dom da paz na Missa</a></p><h3 id="cordeiro" tabindex="-1">Cordeiro <a class="header-anchor" href="#cordeiro" aria-label="Permalink to &quot;Cordeiro&quot;">​</a></h3><ul><li>Iniciar imediatamente após a oração da Paz.</li><li>Não se canta o Cordeiro na celebração da Palavra</li></ul><h3 id="comunhao" tabindex="-1">Comunhão <a class="header-anchor" href="#comunhao" aria-label="Permalink to &quot;Comunhão&quot;">​</a></h3><ul><li>Iniciar o canto da Comunhão enquanto o celebrante comunga. (IGMR 86)</li><li>Dar preferência para cantos inspirados na antífona de comunhão contida no Missal ou no Hinário Litúrgico.</li></ul><h3 id="despedida" tabindex="-1">Despedida <a class="header-anchor" href="#despedida" aria-label="Permalink to &quot;Despedida&quot;">​</a></h3><ul><li>Não é previsto nos livros litúrgicos</li><li>Tradicionalmente pode-se cantar uma das antífonas marianas</li><li>Cuidar para que este canto não contenha desvios doutrinários.</li></ul><h2 id="celebracao-da-palavra" tabindex="-1">Celebração da Palavra <a class="header-anchor" href="#celebracao-da-palavra" aria-label="Permalink to &quot;Celebração da Palavra&quot;">​</a></h2><ul><li>Na celebração da Palavra (celebrada por um ministro ou pelo diácono) após a oferta deve ser cantado um canto de <strong>Louvor</strong> à escolha do grupo de canto.</li><li>Sugestões: <ul><li>Refrão do Salmo</li><li>A Tí Meu Deus</li><li>Te Louvo Em Verdade</li><li>Bom é louvar o Senhor, Nosso Deus</li></ul></li></ul><h2 id="preparacao-para-as-missas" tabindex="-1">Preparação para as Missas <a class="header-anchor" href="#preparacao-para-as-missas" aria-label="Permalink to &quot;Preparação para as Missas&quot;">​</a></h2><ul><li>O grupo de canto deve conhecer o contexto (Tempo, Festa, Solenidade) que será celebrado.</li><li>Meditar as antífonas e leituras propostas para o dia, elas serão base para escolha dos refrãos orantes e cantos.</li><li>Ensaiar ao menos uma vez (quando os cantos forem todos conhecidos) e ao menos duas vezes (quando precisar aprender cantos novos).</li><li>Contribui para um bom ensaio que os membros ouçam a versão original e aprendam o canto antes do ensaio, principalmente no caso dos instrumentistas.</li><li>Objetivos do ensaio <ul><li>Alinhar a melodia dos cantos entre os cantores.</li><li>Ajustar o TOM da música para se adequar às vozes.</li><li>Alinhar o tempo das músicas (velocidade, andamento) entre cantores e instrumentistas.</li></ul></li></ul><h2 id="sobre-o-tom-das-musicas" tabindex="-1">Sobre o Tom das músicas <a class="header-anchor" href="#sobre-o-tom-das-musicas" aria-label="Permalink to &quot;Sobre o Tom das músicas&quot;">​</a></h2><ul><li>A voz deve ter prioridade na definição do tom.</li><li>O tom da música deve ser adequado à tessitura da voz de quem canta.</li><li>É possível que seja necessário encontrar um meio-termo, pois pessoas diferentes têm extensões vocais diferentes, o que dificulta ou facilita a entonação em determinadas partes da música.</li></ul><h2 id="sobre-a-melodia-do-salmo-e-aclamacao" tabindex="-1">Sobre a melodia do Salmo e Aclamação <a class="header-anchor" href="#sobre-a-melodia-do-salmo-e-aclamacao" aria-label="Permalink to &quot;Sobre a melodia do Salmo e Aclamação&quot;">​</a></h2><ul><li><p>Deve-se escolher melodias de fácil execução, que a assembleia possa ouvir uma única vez e reproduzi-la imediatamente.</p></li><li><p>A melodia deve evitar longas pausas.</p></li><li><p>Evitar excesso de melismas.</p></li><li><p>Missas Feriais são as celebrações eucarísticas que acontecem nos dias de semana e aos sábados antes das 18:00 desde que não sejam Festas ou Solenidades.</p></li></ul>',43)])])}const p=e(s,[["render",l]]);export{h as __pageData,p as default};
